<script>
/* ============================================================
   Shared coin renderer (2D canvas, procedural metallic look)
   ============================================================ */
function makeCoinRenderer(canvas, opts){
  const ctx = canvas.getContext('2d');
  let W=0,H=0,DPR=1;
  function resize(){
    DPR = Math.min(2, window.devicePixelRatio||1);
    const r = canvas.getBoundingClientRect();
    W = Math.max(2, r.width); H = Math.max(2, r.height);
    canvas.width = Math.round(W*DPR);
    canvas.height = Math.round(H*DPR);
    ctx.setTransform(DPR,0,0,DPR,0,0);
  }
  resize();
  window.addEventListener('resize', resize);

  // metal palette
  const metals = {
    bronze:  {base:[184,115,51], hi:[255,214,150], lo:[92,52,20], edge:[120,70,30]},
    silver:  {base:[201,210,220],hi:[255,255,255],lo:[120,130,142],edge:[150,160,172]},
    gold:    {base:[217,178,90], hi:[255,233,168],lo:[120,90,30], edge:[160,120,40]},
    black:   {base:[40,44,54],   hi:[150,160,180],lo:[10,12,16],  edge:[30,34,42]},
  };
  const m = metals[opts.metal] || metals.gold;

  // deterministic pseudo-random for relief dots
  function rnd(i){ const x=Math.sin(i*127.1+opts.seed*13.7)*43758.5453; return x-Math.floor(x); }

  // draw a single face (front/back) given a 2D transform already applied
  function drawFace(face, R, lightAngle){
    // base radial metal
    const g = ctx.createRadialGradient(-R*0.3,-R*0.35,R*0.1, 0,0,R);
    g.addColorStop(0, rgb(m.hi));
    g.addColorStop(0.35, rgb(m.base));
    g.addColorStop(1, rgb(m.lo));
    ctx.beginPath(); ctx.arc(0,0,R,0,Math.PI*2); ctx.fillStyle=g; ctx.fill();

    // reeded edge ring (inner)
    ctx.save();
    ctx.beginPath(); ctx.arc(0,0,R*0.97,0,Math.PI*2); ctx.clip();
    const reeds = 90;
    for(let i=0;i<reeds;i++){
      const a = i/reeds*Math.PI*2;
      const x1=Math.cos(a)*R*0.90, y1=Math.sin(a)*R*0.90;
      const x2=Math.cos(a)*R*0.99, y2=Math.sin(a)*R*0.99;
      ctx.strokeStyle = (i%2? rgb(m.lo):rgb(m.hi));
      ctx.lineWidth = R*0.02;
      ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y2); ctx.stroke();
    }
    ctx.restore();

    // outer rim
    ctx.lineWidth=R*0.05; ctx.strokeStyle=rgb(m.edge);
    ctx.beginPath(); ctx.arc(0,0,R*0.95,0,Math.PI*2); ctx.stroke();
    ctx.lineWidth=R*0.015; ctx.strokeStyle=rgb(m.hi);
    ctx.beginPath(); ctx.arc(0,0,R*0.92,0,Math.PI*2); ctx.stroke();

    // embossed content
    ctx.save();
    ctx.translate(0,0);
    if(face==='front'){
      // skull emblem (raised)
      emboss(()=>{
        // head
        ctx.beginPath();
        ctx.ellipse(0,-R*0.05,R*0.30,R*0.34,0,0,Math.PI*2);
        ctx.fill();
        // jaw
        ctx.beginPath();
        ctx.moveTo(-R*0.16,R*0.18); ctx.lineTo(R*0.16,R*0.18);
        ctx.lineTo(R*0.10,R*0.34); ctx.lineTo(-R*0.10,R*0.34); ctx.closePath();
        ctx.fill();
        // eyes
        ctx.globalCompositeOperation='destination-out';
        ctx.beginPath(); ctx.arc(-R*0.12,-R*0.08,R*0.09,0,Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(R*0.12,-R*0.08,R*0.09,0,Math.PI*2); ctx.fill();
        ctx.globalCompositeOperation='source-over';
        // nose
        ctx.beginPath(); ctx.moveTo(0,R*0.0); ctx.lineTo(-R*0.05,R*0.12);
        ctx.lineTo(R*0.05,R*0.12); ctx.closePath(); ctx.fill();
        // teeth lines
        ctx.strokeStyle=rgb(m.lo); ctx.lineWidth=R*0.02;
        for(let i=-2;i<=2;i++){
          ctx.beginPath(); ctx.moveTo(i*R*0.05,R*0.20); ctx.lineTo(i*R*0.05,R*0.32); ctx.stroke();
        }
      }, R);
      // text ring
      ringText("WASTEDTOKEN MINT", R*0.78, R*0.10, -Math.PI/2, true);
      ringText("EST. 2025", R*0.78, R*0.10, Math.PI/2, false);
    } else {
      // denomination
      emboss(()=>{
        ctx.fillStyle=rgb(m.base);
        ctx.font = `900 ${R*0.34}px ui-sans-serif,system-ui,Arial`;
        ctx.textAlign='center'; ctx.textBaseline='middle';
        ctx.fillText(opts.denom.split(' ')[0], 0, -R*0.06);
        ctx.font = `800 ${R*0.12}px ui-sans-serif,system-ui,Arial`;
        ctx.fillText(opts.denom.split(' ').slice(1).join(' '), 0, R*0.22);
      }, R);
      ringText("COLLECTIBLE COIN", R*0.78, R*0.10, -Math.PI/2, true);
      ringText("NOT FINANCIAL", R*0.78, R*0.10, Math.PI/2, false);
    }
    ctx.restore();

    // moving specular highlight (rakes across)
    const hx = Math.cos(lightAngle)*R*1.1;
    const hy = Math.sin(lightAngle)*R*0.5 - R*0.1;
    const sg = ctx.createRadialGradient(hx,hy,0, hx,hy,R*0.9);
    sg.addColorStop(0,'rgba(255,255,255,0.55)');
    sg.addColorStop(0.4,'rgba(255,255,255,0.12)');
    sg.addColorStop(1,'rgba(255,255,255,0)');
    ctx.save();
    ctx.beginPath(); ctx.arc(0,0,R*0.95,0,Math.PI*2); ctx.clip();
    ctx.fillStyle=sg; ctx.fillRect(-R,-R,R*2,R*2);
    ctx.restore();
  }

  function emboss(fn, R){
    // shadow
    ctx.save();
    ctx.translate(R*0.012,R*0.018);
    ctx.fillStyle='rgba(0,0,0,0.45)';
    fn();
    ctx.restore();
    // face
    ctx.save();
    ctx.fillStyle=rgb(m.base);
    fn();
    ctx.restore();
    // top light
    ctx.save();
    ctx.translate(-R*0.01,-R*0.014);
    ctx.fillStyle='rgba(255,255,255,0.25)';
    fn();
    ctx.restore();
  }

  function ringText(txt, radius, size, startAngle, top){
    ctx.save();
    ctx.font = `800 ${size}px ui-sans-serif,system-ui,Arial`;
    ctx.fillStyle = rgb(m.edge);
    ctx.textAlign='center'; ctx.textBaseline='middle';
    const step = (Math.PI*2)/txt.length;
    for(let i=0;i<txt.length;i++){
      const a = startAngle + (top? i*step : -i*step);
      ctx.save();
      ctx.rotate(a);
      ctx.translate(0,-radius);
      ctx.fillText(txt[i],0,0);
      ctx.restore();
    }
    ctx.restore();
  }

  function rgb(c){return `rgb(${c[0]|0},${c[1]|0},${c[2]|0})`;}

  // main render: t in [0,1)
  function render(t){
    if(!W) resize();
    ctx.clearRect(0,0,W,H);
    const cx=W/2, cy=H/2;
    const R = Math.min(W,H)*0.36;

    // rotation: vertical spin + horizontal flip
    const spin = t*Math.PI*2;            // around vertical
    const flip = Math.sin(t*Math.PI*2);  // -1..1 around horizontal
    const cosF = Math.abs(flip);
    const face = flip>=0 ? 'front':'back';
    // light angle rakes with spin
    const lightAngle = spin*1.0 + Math.PI*0.25;

    ctx.save();
    ctx.translate(cx,cy);
    // scaleX by cos(spin) gives 3D turn; scaleY by flip gives flip
    const sx = Math.cos(spin);
    const sy = flip;
    ctx.scale(sx, sy);
    // when edge-on, draw reeded edge cylinder
    const edgeW = Math.abs(Math.cos(spin))*R;
    if(edgeW < R*0.18){
      // draw thin edge
      ctx.save();
      ctx.scale(1,1);
      const eg = ctx.createLinearGradient(-R,0,R,0);
      eg.addColorStop(0,rgb(m.lo)); eg.addColorStop(.5,rgb(m.hi)); eg.addColorStop(1,rgb(m.lo));
      ctx.fillStyle=eg;
      ctx.fillRect(-R*0.12,-R,R*0.24,R*2);
      // reeds
      for(let i=0;i<24;i++){
        ctx.strokeStyle = i%2? rgb(m.lo):rgb(m.hi);
        ctx.lineWidth=R*0.02;
        const y=-R + i*(R*2/24);
        ctx.beginPath(); ctx.moveTo(-R*0.12,y); ctx.lineTo(R*0.12,y); ctx.stroke();
      }
      ctx.restore();
    } else {
      drawFace(face, R, lightAngle);
    }
    ctx.restore();
  }
  return {render, resize};
}

/* ============================================================
   Hero coin
   ============================================================ */
const hero = document.getElementById('coin-hero');
const heroR = makeCoinRenderer(hero, {metal:'gold', denom:'10,000 TOKENS', seed:7});
window.demo = {
  canvas: hero,
  setTime(t){ heroR.render(((t%1)+1)%1); },
  pause(){ stopped=true; }
};
let stopped=false;
let t0=performance.now();
let userT=null;
function loop(now){
  if(stopped) return;
  const t = userT!=null ? userT : (((now-t0)/9000)%1);
  heroR.render(t);
  requestAnimationFrame(loop);
}
requestAnimationFrame(loop);

// drag to spin
let dragging=false, lastX=0, dragT=0;
hero.addEventListener('pointerdown',e=>{dragging=true;lastX=e.clientX;dragT=((performance.now()-t0)/9000)%1;userT=dragT;hero.setPointerCapture(e.pointerId);});
hero.addEventListener('pointermove',e=>{
  if(!dragging)return;
  const dx=e.clientX-lastX; lastX=e.clientX;
  dragT=(dragT+dx/600)%1; userT=((dragT%1)+1)%1; heroR.render(userT);
});
hero.addEventListener('pointerup',e=>{dragging=false; t0=performance.now()-userT*9000; userT=null;});

/* ============================================================
   Collection grid
   ============================================================ */
const editions = [
  {key:'bronze', name:'Bronze Drift', metal:'bronze', state:'available',
   denom:'1,000 TOKENS', price:'0.08 ETH', note:'Available now'},
  {key:'silver', name:'Silver Relapse', metal:'silver', state:'available',
   denom:'5,000 TOKENS', price:'0.22 ETH', note:'Available now'},
  {key:'gold', name:'Gold Bender', metal:'gold', state:'sold-out',
   denom:'10,000 TOKENS', price:'0.75 ETH', note:'SOLD OUT — fully struck'},
  {key:'black', name:'Obsidian Comedown', metal:'black', state:'coming-soon',
   denom:'25,000 TOKENS', price:'TBA', note:'MINTING NEXT SEASON: Winter 2025'},
];
const grid=document.getElementById('grid');
const toast=document.getElementById('toast');
editions.forEach(ed=>{
  const div=document.createElement('div');
  div.className='edition';
  div.dataset.edition=ed.key;
  div.dataset.state=ed.state;
  const badge = ed.state==='available'?'AVAILABLE':ed.state==='sold-out'?'SOLD OUT':'COMING SOON';
  div.innerHTML = `
    <div class="badge ${ed.state}">${badge}</div>
    <canvas class="edition-canvas"></canvas>
    <h3>${ed.name}</h3>
    <div class="meta">${ed.note}<br><span class="price">${ed.price}</span></div>
  `;
  grid.appendChild(div);
  const cv=div.querySelector('.edition-canvas');
  const r=makeCoinRenderer(cv,{metal:ed.metal, denom:ed.denom, seed:ed.key.length*3+5});
  // gentle idle animation per tile
  let pt=Math.random();
  (function anim(){
    pt=(pt+0.0016)%1; r.render(pt); requestAnimationFrame(anim);
  })();
  if(ed.state==='available'){
    const b=document.createElement('button');
    b.className='buy'; b.textContent='Add to cart';
    b.addEventListener('click',()=>{
      toast.textContent='Added: '+ed.name; toast.classList.add('show');
      setTimeout(()=>toast.classList.remove('show'),1400);
    });
    div.appendChild(b);
  }
});
</script>
